con:config.script:
def franchiseName = context.expand('${franchiseName#Result}')
def textNum = Math.abs(new Random().nextInt() % 99999) + 1 def textNum2 = franchiseName + '_'+textNum
return textNum2

TimeZone.setDefault(TimeZone.getTimeZone('UTC'))
use(groovy.time.TimeCategory) {
    def date1 = new Date() - 1.day - 4.hour + 0.minutes
    def dateFrom = date1.format("yyyy-MM-dd'T'HH:mm:ss.SS'Z'")
    log.info date1
    return dateFrom
}

import groovy.json.*
import org.apache.commons.lang.RandomStringUtils 

def val1 = context.expand('${cc_walletIDs#ResponseAsXml}')
def val2 = new XmlSlurper().parseText(val1)

log.info val1

def cc_Ids = []
/*
val2.ResultSet.Row.each(){row -> cc_Ids.add(row.COST_CENTER.ID)}

*/
val2.'**'.findAll { node -> node.name() == 'Row' }.each { row ->
    row.'**'.findAll { node -> node.name() == 'COST_CENTER.ID' }.each { id ->
        cc_Ids.add(id.text())
    }
}
log.info cc_Ids

def number = cc_Ids.size()
//log.info number

for (i =0; i<number; i++){
		//Collections.shuffle(walletIds)
		def ccIDS =  cc_Ids[i] as String
		testRunner.testCase.testSteps['Properties'].setPropertyValue("costCentersID"+i, ccIDS)
}
//log.info cc_Ids
return cc_Ids

import groovy.json.*
import org.apache.commons.lang.RandomStringUtils 

def val1 = context.expand('${cc_walletIDs#ResponseAsXml}')
def val2 = new XmlSlurper().parseText(val1)

//log.info val2

def cc_name = []
val2.'**'.findAll { node -> node.name() == 'Row' }.each { row ->
    row.'**'.findAll { node -> node.name() == 'COST_CENTER.NAME' }.each { id ->
        cc_name.add(id.text())
    }
}


def number = cc_name.size()

for (i =0; i<number; i++){
		//Collections.shuffle(walletIds)
		def ccName =  cc_name[i] as String
		log.info ccName
		testRunner.testCase.testSteps['Properties'].setPropertyValue("cc_name"+i, ccName)
}
return cc_name

// === Collect all terminalID0, terminalID1... and save to "Result" ===
def props = testRunner.testCase.testSteps['Properties']

def terminalList = []
def idx = 0

while (true) {
    def propName = "cc_name${idx}"
    def value = props.getPropertyValue(propName)

    if (value == null || value.trim() == "") {
        break
    }

    terminalList << value.trim()
    idx++
}

if (terminalList.size() > 0) {
    def resultValue = terminalList.toString()   // creates [id1, id2, id3, ...]

    props.setPropertyValue("Result", resultValue)
    props.setPropertyValue("ccIDs", resultValue)

    log.info "✅ SUCCESS: Saved ${terminalList.size()} terminals to Result"
    log.info resultValue
} else {
    log.error "No ccIDs properties found!"
}
